#include <stdio.h>
#include <stdlib.h>

int compare(const void *a, const void *b) {
    return (*(int*)a - *(int*)b);
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, P, Q;
        scanf("%d %d %d", &N, &P, &Q);
        int A[N];
        for (int i = 0; i < N; i++) {
            scanf("%d", &A[i]);
        }
        qsort(A, N, sizeof(int), compare);
        int paid = 0;
        for (int i = 0; i < N; i++) {
            if (A[i] == 1 && P > 0) {
                paid++;
                P--;
            } else if (A[i] == 2 && Q > 0) {
                paid++;
                Q--;
            } else if (A[i] > 2 && P >= A[i]) {
                paid++;
                P -= A[i];
            } else if (A[i] > 2 && Q * 2 + P >= A[i]) {
                paid++;
                Q -= (A[i] - P) / 2;
                P -= A[i] % 2;
            }
        }
        printf("%d\n", paid);
    }
    return 0;
}

